NEW_FILES = [
    ('backend/routers/integrity_router.py',
     '"""\nintegrity_router — v333 System Integrity briefing + feed\n=========================================================\nOperator-approved (2026-06-12): "morning report" infrastructure inside the\nbriefings panel + regime demotions auditable with before/after stops.\n\nGET /api/integrity/morning-report\n    Session scorecard with PASS/WARN/FAIL checks proving this week\'s\n    fixes are holding:\n      • scalps fired today (v328 unblocked the blackout that zeroed them)\n      • data uptime — % of RTH minutes with ≥1 ingest write (pusher\n        liveness; the 2026-06-12 blackout would read ~0%)\n      • snapshot freshness — age of the newest ingest write\n      • daily-bar leak — in-progress daily bars for today (v328: must be 0\n        before the close)\n      • RTH backfill gate — deep requests currently held (v328)\n      • M0 ladder — trades carrying multi-leg OCA ladders + legs filled\n      • regime — current regime + demotions today (v332)\n      • integrity events today by severity\n\nGET /api/integrity/feed?limit=30\n    Recent state_integrity_events (newest first) PLUS per-trade regime\n    demotion stop moves (old → new stop) pulled from\n    bot_trades.trailing_stop_config.stop_adjustments, merged into one\n    auditable timeline.\n"""\nimport asyncio\nimport logging\nfrom datetime import datetime, timedelta, timezone\nfrom typing import Any, Dict, List, Optional\nfrom zoneinfo import ZoneInfo\n\nfrom fastapi import APIRouter, Query\n\nlogger = logging.getLogger(__name__)\n\nrouter = APIRouter(prefix="/api/integrity", tags=["integrity"])\n\n_db = None\nET = ZoneInfo("America/New_York")\n\n\ndef init_integrity_router(db) -> None:\n    global _db\n    _db = db\n\n\ndef _today_bounds():\n    now_et = datetime.now(ET)\n    open_et = now_et.replace(hour=9, minute=30, second=0, microsecond=0)\n    close_et = now_et.replace(hour=16, minute=0, second=0, microsecond=0)\n    midnight_et = now_et.replace(hour=0, minute=0, second=0, microsecond=0)\n    return now_et, open_et, close_et, midnight_et\n\n\ndef _parse_ts(v) -> Optional[datetime]:\n    if isinstance(v, datetime):\n        return v if v.tzinfo else v.replace(tzinfo=timezone.utc)\n    try:\n        dt = datetime.fromisoformat(str(v).replace("Z", "+00:00"))\n        return dt if dt.tzinfo else dt.replace(tzinfo=timezone.utc)\n    except Exception:\n        return None\n\n\ndef _check(name: str, status: str, value: str, detail: str = "") -> Dict[str, Any]:\n    return {"name": name, "status": status, "value": value, "detail": detail}\n\n\ndef _sync_morning_report() -> Dict[str, Any]:\n    now_et, open_et, close_et, midnight_et = _today_bounds()\n    today_str = now_et.strftime("%Y-%m-%d")\n    midnight_utc_iso = midnight_et.astimezone(timezone.utc).isoformat()\n    open_utc_iso = open_et.astimezone(timezone.utc).isoformat()\n    checks: List[Dict[str, Any]] = []\n\n    # ── 1. trades fired today by style ───────────────────────────────────\n    style_counts: Dict[str, int] = {}\n    for doc in _db["bot_trades"].find(\n        {"created_at": {"$gte": midnight_utc_iso}},\n        {"_id": 0, "trade_style": 1},\n    ):\n        s = doc.get("trade_style") or "?"\n        style_counts[s] = style_counts.get(s, 0) + 1\n    scalps = style_counts.get("scalp", 0)\n    total_trades = sum(style_counts.values())\n    in_session = open_et <= now_et <= close_et and now_et.weekday() < 5\n    if not in_session and total_trades == 0:\n        checks.append(_check("scalps_fired", "info", "market closed",\n                             "no session today / pre-open"))\n    else:\n        checks.append(_check(\n            "scalps_fired",\n            "pass" if scalps > 0 else ("warn" if in_session and now_et > open_et + timedelta(hours=1) else "info"),\n            f"{scalps} scalps / {total_trades} total",\n            " · ".join(f"{k}:{v}" for k, v in sorted(style_counts.items())) or "no entries yet",\n        ))\n\n    # ── 2. data uptime (distinct ingest minutes vs RTH minutes elapsed) ──\n    minutes_seen = set()\n    newest_ingest: Optional[datetime] = None\n    for doc in _db["ib_historical_data"].find(\n        {"collected_at": {"$gte": open_utc_iso}},\n        {"_id": 0, "collected_at": 1},\n    ):\n        ts = _parse_ts(doc.get("collected_at"))\n        if not ts:\n            continue\n        if newest_ingest is None or ts > newest_ingest:\n            newest_ingest = ts\n        ts_et = ts.astimezone(ET)\n        mins = ts_et.hour * 60 + ts_et.minute\n        if 9 * 60 + 30 <= mins <= 16 * 60:\n            minutes_seen.add(ts_et.strftime("%H:%M"))\n    elapsed_min = max(0, int((min(now_et, close_et) - open_et).total_seconds() // 60))\n    if elapsed_min <= 0 or now_et.weekday() >= 5:\n        checks.append(_check("data_uptime", "info", "—", "outside RTH"))\n        uptime_pct = None\n    else:\n        uptime_pct = round(100.0 * len(minutes_seen) / max(1, elapsed_min), 1)\n        checks.append(_check(\n            "data_uptime",\n            "pass" if uptime_pct >= 80 else ("warn" if uptime_pct >= 40 else "fail"),\n            f"{uptime_pct}%",\n            f"{len(minutes_seen)}/{elapsed_min} RTH minutes with ingest",\n        ))\n\n    # ── 3. snapshot freshness ─────────────────────────────────────────────\n    if newest_ingest is None:\n        newest_doc = _db["ib_historical_data"].find_one(\n            {}, {"_id": 0, "collected_at": 1}, sort=[("collected_at", -1)])\n        newest_ingest = _parse_ts((newest_doc or {}).get("collected_at"))\n    if newest_ingest:\n        age_s = int((datetime.now(timezone.utc) - newest_ingest).total_seconds())\n        if in_session:\n            status = "pass" if age_s <= 120 else ("warn" if age_s <= 600 else "fail")\n        else:\n            status = "info"\n        checks.append(_check("ingest_freshness", status,\n                             f"{age_s}s ago" if age_s < 3600 else f"{age_s // 3600}h ago",\n                             "newest ib_historical_data write"))\n    else:\n        checks.append(_check("ingest_freshness", "fail", "none", "no ingest rows found"))\n\n    # ── 4. daily-bar leak (v328 must hold) ────────────────────────────────\n    leak_n = _db["ib_historical_data"].count_documents(\n        {"bar_size": "1 day", "date": {"$regex": f"^{today_str}"}})\n    if now_et >= close_et.replace(minute=15):\n        checks.append(_check("daily_bar_leak", "info", f"{leak_n} today",\n                             "post-close — today\'s daily bar is legitimately final"))\n    else:\n        checks.append(_check("daily_bar_leak", "pass" if leak_n == 0 else "fail",\n                             f"{leak_n} leaked",\n                             "in-progress daily bars for today (v328 guard: must be 0)"))\n\n    # ── 5. RTH backfill gate ──────────────────────────────────────────────\n    try:\n        from services.historical_data_queue_service import (\n            _rth_backfill_gate_active, _deep_request_exclusion)\n        gate_on = _rth_backfill_gate_active()\n        deep_held = _db["historical_data_requests"].count_documents(\n            {"status": "pending", "$nor": [{"$and": _deep_request_exclusion()}]})\n        checks.append(_check(\n            "backfill_gate", "pass" if (gate_on or not in_session) else "warn",\n            "ACTIVE" if gate_on else "off",\n            f"{deep_held} deep request(s) held until after close" if gate_on\n            else f"{deep_held} deep request(s) pending (gate off)",\n        ))\n    except Exception as e:\n        checks.append(_check("backfill_gate", "warn", "unknown", str(e)[:80]))\n\n    # ── 6. M0 ladder activity today ───────────────────────────────────────\n    ladder_trades = 0\n    legs_filled = 0\n    for doc in _db["bot_trades"].find(\n        {"created_at": {"$gte": midnight_utc_iso},\n         "scale_out_config.m0_legs": {"$exists": True, "$ne": []}},\n        {"_id": 0, "scale_out_config.m0_legs.status": 1},\n    ):\n        ladder_trades += 1\n        for leg in (doc.get("scale_out_config") or {}).get("m0_legs", []):\n            if str(leg.get("status")) == "filled":\n                legs_filled += 1\n    checks.append(_check(\n        "m0_ladder", "pass" if legs_filled > 0 else "info",\n        f"{ladder_trades} laddered · {legs_filled} legs filled",\n        "multi-leg OCA scale-out validation (M0a-d)",\n    ))\n\n    # ── 7. regime + demotions today (v332) ───────────────────────────────\n    demotions_today = list(_db["state_integrity_events"].find(\n        {"event": "regime_demotion", "ts": {"$gte": midnight_utc_iso}},\n        {"_id": 0}))\n    regime_doc = _db["regime_snapshots"].find_one({}, sort=[("timestamp", -1)]) or {}\n    regime = regime_doc.get("state") or regime_doc.get("regime") or "?"\n    demo_summary = ""\n    if demotions_today:\n        last = demotions_today[-1]\n        demo_summary = (f"{last.get(\'from_regime\')}→{last.get(\'to_regime\')} "\n                        f"stats={last.get(\'stats\')}")\n    checks.append(_check(\n        "regime", "info", f"{regime} · {len(demotions_today)} demotion(s) today",\n        demo_summary or "no demotion passes today"))\n\n    # ── 8. integrity events today by severity ────────────────────────────\n    sev: Dict[str, int] = {}\n    for doc in _db["state_integrity_events"].find(\n        {"ts": {"$gte": midnight_utc_iso}}, {"_id": 0, "severity": 1}):\n        s = doc.get("severity") or "?"\n        sev[s] = sev.get(s, 0) + 1\n    n_events = sum(sev.values())\n    checks.append(_check(\n        "integrity_events",\n        "pass" if sev.get("high", 0) == 0 else "warn",\n        f"{n_events} today",\n        " · ".join(f"{k}:{v}" for k, v in sorted(sev.items())) or "clean",\n    ))\n\n    n_pass = sum(1 for c in checks if c["status"] == "pass")\n    n_fail = sum(1 for c in checks if c["status"] == "fail")\n    n_warn = sum(1 for c in checks if c["status"] == "warn")\n    scored = sum(1 for c in checks if c["status"] in ("pass", "warn", "fail"))\n    verdict = "FAIL" if n_fail else ("WARN" if n_warn else "PASS")\n\n    return {\n        "success": True,\n        "generated_at": datetime.now(timezone.utc).isoformat(),\n        "session_date": today_str,\n        "in_session": in_session,\n        "verdict": verdict,\n        "score": f"{n_pass}/{scored}",\n        "checks": checks,\n        "uptime_pct": uptime_pct,\n        "scalps_today": scalps,\n        "trades_today": total_trades,\n        "leaked_daily_bars": leak_n,\n        "demotions_today": len(demotions_today),\n    }\n\n\ndef _sync_feed(limit: int) -> Dict[str, Any]:\n    items: List[Dict[str, Any]] = []\n\n    for doc in _db["state_integrity_events"].find(\n        {}, {"_id": 0}).sort("ts", -1).limit(limit):\n        ev = doc.get("event") or "?"\n        if ev == "regime_demotion":\n            stats = doc.get("stats") or {}\n            text = (f"Regime {doc.get(\'from_regime\')} → {doc.get(\'to_regime\')} "\n                    f"confirmed — {stats.get(\'be\', 0)} to BE, "\n                    f"{stats.get(\'tightened\', 0)} tightened"\n                    + (f" [{\', \'.join(doc.get(\'details\') or [])}]"\n                       if doc.get("details") else ""))\n        else:\n            text = doc.get("text") or doc.get("detail") or ev\n        items.append({"ts": doc.get("ts"), "event": ev,\n                      "severity": doc.get("severity") or "info",\n                      "symbol": doc.get("symbol"), "text": text})\n\n    # merge per-trade regime-demotion stop moves (old → new, auditable)\n    cutoff = (datetime.now(timezone.utc) - timedelta(days=14)).isoformat()\n    for doc in _db["bot_trades"].find(\n        {"trailing_stop_config.stop_adjustments.reason":\n            {"$regex": "^regime_demotion"},\n         "created_at": {"$gte": cutoff}},\n        {"_id": 0, "symbol": 1, "trailing_stop_config.stop_adjustments": 1},\n    ).limit(50):\n        for adj in (doc.get("trailing_stop_config") or {}).get("stop_adjustments", []):\n            if not str(adj.get("reason", "")).startswith("regime_demotion"):\n                continue\n            items.append({\n                "ts": adj.get("timestamp"),\n                "event": "regime_demotion_stop_move",\n                "severity": "medium",\n                "symbol": doc.get("symbol"),\n                "text": (f"{doc.get(\'symbol\')} stop ${adj.get(\'old_stop\'):.2f} → "\n                         f"${adj.get(\'new_stop\'):.2f} ({adj.get(\'reason\')}) "\n                         f"@ px ${adj.get(\'price_at_adjustment\') or 0:.2f}"),\n            })\n\n    items.sort(key=lambda x: str(x.get("ts") or ""), reverse=True)\n    return {"success": True, "count": len(items[:limit]), "items": items[:limit]}\n\n\n@router.get("/morning-report")\nasync def get_morning_report():\n    if _db is None:\n        return {"success": False, "error": "db not initialised"}\n    try:\n        return await asyncio.to_thread(_sync_morning_report)\n    except Exception as e:\n        logger.error(f"morning-report failed: {e}", exc_info=True)\n        return {"success": False, "error": str(e)[:200]}\n\n\n@router.get("/feed")\nasync def get_integrity_feed(limit: int = Query(30, ge=1, le=200)):\n    if _db is None:\n        return {"success": False, "error": "db not initialised"}\n    try:\n        return await asyncio.to_thread(_sync_feed, limit)\n    except Exception as e:\n        logger.error(f"integrity feed failed: {e}", exc_info=True)\n        return {"success": False, "error": str(e)[:200]}\n'),
    ('frontend/src/components/sentcom/v5/IntegrityCardV5.jsx',
     '/**\n * IntegrityCardV5 — v333 "System Integrity" briefing surfaces.\n *\n * Exports:\n *   useIntegrityReport — shared polling hook (morning-report + feed)\n *   IntegrityBody      — checklist + integrity feed (regime demotions\n *                        with before/after stops); used by the briefing\n *                        deep-dive modal (briefingKey="integrity")\n *   IntegrityCardV5    — compact always-on card for the BriefingsV5 panel\n *\n * Backend: GET /api/integrity/morning-report + GET /api/integrity/feed.\n * A live pass/fail scorecard proving the pipeline fixes are holding —\n * scalp count, data uptime, ingest freshness, daily-bar leak (v328),\n * RTH backfill gate, M0 ladder fills, regime + demotions (v332).\n */\nimport React, { useEffect, useState, useCallback } from \'react\';\nimport api from \'../../../utils/api\';\n\nconst STATUS_STYLE = {\n  pass: \'text-emerald-400\',\n  warn: \'text-amber-400\',\n  fail: \'text-rose-400\',\n  info: \'text-zinc-500\',\n};\n\nconst STATUS_ICON = { pass: \'✓\', warn: \'!\', fail: \'✗\', info: \'·\' };\n\nconst CHECK_LABEL = {\n  scalps_fired: \'Scalps fired\',\n  data_uptime: \'Data uptime\',\n  ingest_freshness: \'Ingest freshness\',\n  daily_bar_leak: \'Daily-bar leak\',\n  backfill_gate: \'Backfill gate\',\n  m0_ladder: \'M0 ladder\',\n  regime: \'Regime\',\n  integrity_events: \'Integrity events\',\n};\n\nconst fmtFeedTs = (ts) => {\n  try {\n    return new Date(ts).toLocaleTimeString(\'en-US\', {\n      timeZone: \'America/New_York\', hour: \'numeric\', minute: \'2-digit\', hour12: true,\n    });\n  } catch {\n    return \'\';\n  }\n};\n\nexport const useIntegrityReport = ({ enabled = true, refreshMs = 60000 } = {}) => {\n  const [report, setReport] = useState(null);\n  const [feed, setFeed] = useState([]);\n  const [loading, setLoading] = useState(true);\n\n  const reload = useCallback(async () => {\n    try {\n      const [rep, fd] = await Promise.allSettled([\n        api.get(\'/api/integrity/morning-report\', { timeout: 12000 }),\n        api.get(\'/api/integrity/feed?limit=15\', { timeout: 12000 }),\n      ]);\n      if (rep.status === \'fulfilled\' && rep.value.data?.success) setReport(rep.value.data);\n      if (fd.status === \'fulfilled\' && fd.value.data?.success) setFeed(fd.value.data.items || []);\n    } finally {\n      setLoading(false);\n    }\n  }, []);\n\n  useEffect(() => {\n    if (!enabled) return undefined;\n    reload();\n    if (!refreshMs) return undefined;\n    const id = setInterval(reload, refreshMs);\n    return () => clearInterval(id);\n  }, [enabled, refreshMs, reload]);\n\n  return { report, feed, loading, reload };\n};\n\nconst Checklist = ({ checks }) => (\n  <div className="space-y-1 text-[13px]" data-testid="integrity-checklist">\n    {(checks || []).map((c) => (\n      <div key={c.name} className="flex justify-between gap-3">\n        <span className="text-zinc-400 min-w-0">\n          <span className={`v5-mono ${STATUS_STYLE[c.status] || \'text-zinc-500\'}`}>\n            {STATUS_ICON[c.status] || \'·\'}\n          </span>{\' \'}\n          {CHECK_LABEL[c.name] || c.name}\n          {c.detail && <span className="text-zinc-600"> — {c.detail}</span>}\n        </span>\n        <span className={`whitespace-nowrap v5-mono ${STATUS_STYLE[c.status] || \'text-zinc-400\'}`}>\n          {c.value}\n        </span>\n      </div>\n    ))}\n  </div>\n);\n\nconst FeedList = ({ feed, maxHeight = \'max-h-56\' }) => (\n  <div className={`${maxHeight} overflow-y-auto v5-scroll space-y-0.5 text-[13px]`} data-testid="integrity-feed">\n    {feed.length === 0 && <div className="text-zinc-600">No integrity events recorded.</div>}\n    {feed.map((it, i) => (\n      <div key={`${it.ts}-${i}`} className="flex gap-2">\n        <span className="v5-mono text-zinc-600 whitespace-nowrap">{fmtFeedTs(it.ts)}</span>\n        <span className={\n          it.severity === \'high\' ? \'text-rose-400\'\n            : it.severity === \'medium\' ? \'text-amber-400\' : \'text-zinc-400\'\n        }>\n          {it.text}\n        </span>\n      </div>\n    ))}\n  </div>\n);\n\n/** Full deep-dive body — rendered inside the briefing modal. */\nexport const IntegrityBody = () => {\n  const { report, feed, loading } = useIntegrityReport({ refreshMs: 60000 });\n  const verdict = report?.verdict;\n  const verdictCls = verdict === \'PASS\' ? \'v5-up\' : verdict === \'WARN\' ? \'v5-warn\' : \'v5-down\';\n\n  return (\n    <section data-testid="briefing-section-integrity" className="border-t border-zinc-800">\n      <div className="flex items-center justify-between px-4 py-2 border-b border-zinc-900 bg-zinc-950/40">\n        <div className="v5-mono text-[13px] font-bold tracking-widest uppercase text-cyan-400">\n          System Integrity\n        </div>\n        {verdict && (\n          <span data-testid="integrity-verdict" className={`v5-mono text-xs font-bold ${verdictCls}`}>\n            {verdict} {report?.score}\n          </span>\n        )}\n      </div>\n      <div className="px-4 py-3 space-y-3">\n        {loading && !report && <div className="text-zinc-500 text-[13px]">Loading…</div>}\n        {!loading && !report && (\n          <div className="text-zinc-500 text-[13px]">Integrity endpoint unavailable.</div>\n        )}\n        {report && <Checklist checks={report.checks} />}\n        <div>\n          <div className="v5-mono text-[12px] text-zinc-500 uppercase tracking-wider mb-1">\n            Integrity feed — automatic risk actions (regime demotions show before → after stops)\n          </div>\n          <FeedList feed={feed} />\n        </div>\n      </div>\n    </section>\n  );\n};\n\n/** Compact always-on card for the BriefingsV5 4-card panel. */\nexport const IntegrityCardV5 = ({ expanded, onToggle }) => {\n  const { report, feed, loading } = useIntegrityReport({ refreshMs: 60000 });\n  const verdict = report?.verdict;\n  const verdictCls = verdict === \'PASS\' ? \'v5-up\' : verdict === \'WARN\' ? \'v5-warn\' : \'v5-down\';\n\n  return (\n    <div data-testid="v5-briefing-integrity" className="v5-briefing-card" onClick={onToggle}>\n      <div className="flex items-center justify-between">\n        <div className="flex items-center gap-2">\n          <span className="v5-mono font-bold text-xs text-cyan-400">SYSTEM INTEGRITY</span>\n          {verdict && (\n            <span className={`v5-mono text-xs font-bold ${verdictCls}`}>\n              {verdict} {report?.score}\n            </span>\n          )}\n        </div>\n        <span className="v5-mono text-[14px] v5-dim">live · 60s</span>\n      </div>\n      <div className="v5-why mt-1" data-testid="integrity-summary">\n        {loading && !report && <span className="text-zinc-500">Loading…</span>}\n        {!loading && !report && <span className="text-zinc-500">Integrity endpoint unavailable.</span>}\n        {report && (\n          <>\n            <span>{report.scalps_today} scalps</span>\n            {report.uptime_pct != null && (\n              <span> · data <span className={report.uptime_pct >= 80 ? \'v5-up\' : report.uptime_pct >= 40 ? \'v5-warn\' : \'v5-down\'}>{report.uptime_pct}%</span></span>\n            )}\n            <span> · leaks <span className={report.leaked_daily_bars === 0 ? \'v5-up\' : \'v5-down\'}>{report.leaked_daily_bars}</span></span>\n            {report.demotions_today > 0 && (\n              <span> · <span className="v5-warn">{report.demotions_today} demotion{report.demotions_today > 1 ? \'s\' : \'\'}</span></span>\n            )}\n          </>\n        )}\n      </div>\n      {expanded && report && (\n        <div className="mt-2 pt-2 border-t border-zinc-800" onClick={(e) => e.stopPropagation()}>\n          <Checklist checks={report.checks} />\n          {feed.length > 0 && (\n            <div className="pt-1 mt-1 border-t border-zinc-800/60">\n              <div className="text-zinc-500 text-[12px] mb-0.5">Integrity feed</div>\n              <FeedList feed={feed} maxHeight="max-h-32" />\n            </div>\n          )}\n        </div>\n      )}\n    </div>\n  );\n};\n\nexport default IntegrityCardV5;\n'),
    ('backend/tests/test_v333_integrity.py',
     '"""v333 — System Integrity briefing infrastructure.\n\nBackend: routers/integrity_router.py\n  GET /api/integrity/morning-report — session scorecard (scalps, data\n      uptime, ingest freshness, daily-bar leak v328, backfill gate,\n      M0 ladder, regime + demotions v332, integrity-event severities)\n  GET /api/integrity/feed — state_integrity_events merged with per-trade\n      regime-demotion stop moves (old → new stop, auditable)\n\nFrontend: Integrity button in BriefingsCompactStrip → deep-dive modal\n  (briefingKey="integrity") renders IntegrityBody at the top of the\n  scroll area; IntegrityCardV5 also added to the BriefingsV5 panel.\n"""\nimport py_compile\nfrom pathlib import Path\n\n\ndef _repo_root():\n    for c in Path(__file__).resolve().parents:\n        if (c / "backend" / "routers" / "integrity_router.py").exists():\n            return c\n    raise AssertionError("repo root not found")\n\n\nROOT = _repo_root()\nROUTER = (ROOT / "backend" / "routers" / "integrity_router.py").read_text()\nSERVER = (ROOT / "backend" / "server.py").read_text()\nSTRIP = (ROOT / "frontend" / "src" / "components" / "sentcom" / "v5" /\n         "BriefingsCompactStrip.jsx").read_text()\nMODAL = (ROOT / "frontend" / "src" / "components" /\n         "MorningBriefingModal.jsx").read_text()\nCARD = (ROOT / "frontend" / "src" / "components" / "sentcom" / "v5" /\n        "IntegrityCardV5.jsx").read_text()\n\n\ndef test_router_compiles_and_has_endpoints():\n    py_compile.compile(str(ROOT / "backend" / "routers" / "integrity_router.py"),\n                       doraise=True)\n    assert \'@router.get("/morning-report")\' in ROUTER\n    assert \'@router.get("/feed")\' in ROUTER\n    assert \'prefix="/api/integrity"\' in ROUTER\n\n\ndef test_router_checks_cover_week_fixes():\n    for check in ("scalps_fired", "data_uptime", "ingest_freshness",\n                  "daily_bar_leak", "backfill_gate", "m0_ladder",\n                  "regime", "integrity_events"):\n        assert f\'"{check}"\' in ROUTER, check\n\n\ndef test_feed_includes_regime_demotion_stop_moves():\n    assert "regime_demotion_stop_move" in ROUTER\n    assert "stop_adjustments" in ROUTER\n    assert "old_stop" in ROUTER and "new_stop" in ROUTER\n\n\ndef test_server_registers_router():\n    assert "from routers.integrity_router import" in SERVER\n    assert "init_integrity_router(db)" in SERVER\n\n\ndef test_strip_has_integrity_button():\n    assert \'"integrity"\' in STRIP or "\'integrity\'" in STRIP\n    assert "ShieldCheck" in STRIP\n    assert "windowStart == null" in STRIP or "windowStart === null" in STRIP \\\n        or "def.windowStart == null" in STRIP\n\n\ndef test_modal_has_integrity_variant_and_body():\n    assert "integrity: {" in MODAL\n    assert "IntegrityBody" in MODAL\n    assert "briefingKey === \'integrity\'" in MODAL\n\n\ndef test_card_exports():\n    assert "export const useIntegrityReport" in CARD\n    assert "export const IntegrityBody" in CARD\n    assert "export const IntegrityCardV5" in CARD\n    assert "data-testid=\\"integrity-feed\\"" in CARD\n'),
]


def find_root() -> Path:
    for cand in [Path.cwd(), *Path(__file__).resolve().parents]:
        if (cand / "backend" / "server.py").exists() and (cand / "frontend").exists():
            return cand
    print("FATAL: run from repo root")
    sys.exit(1)


def apply_all(root: Path) -> int:
    applied = 0
    for rel, old, new in CHUNKS:
        path = root / rel
        text = path.read_text()
        if new in text:
            print(f"[SKIP] {rel} — chunk already applied")
            continue
        n = text.count(old)
        if n != 1:
            print(f"[FAIL] {rel} — anchor found {n}x (expected 1). File drifted. ABORTING.")
            sys.exit(2)
        path.write_text(text.replace(old, new, 1))
        applied += 1
        print(f"[OK]   {rel} — chunk applied")
    for rel, content in NEW_FILES:
        path = root / rel
        if path.exists() and path.read_text() == content:
            print(f"[SKIP] {rel} — already present")
            continue
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content)
        applied += 1
        print(f"[OK]   {rel} — written")
    return applied


def self_test(root: Path) -> None:
    print()
    print("── self-test: pytest ──")
    r = subprocess.run(
        [sys.executable, "-m", "pytest", "-q", "tests/test_v333_integrity.py"],
        cwd=str(root / "backend"), capture_output=True, text=True, timeout=180,
    )
    for line in (r.stdout or "").strip().splitlines()[-3:]:
        print("   " + line)
    if r.returncode != 0:
        print("[FAIL] self-test failed — see above.")
        print((r.stdout or "")[-1500:])
        sys.exit(3)
    print("[OK]   self-test PASSED")


def main():
    root = find_root()
    print(f"repo root: {root}")
    applied = apply_all(root)
    self_test(root)
    print()
    print(f"v333 done — {applied} item(s) newly applied.")
    print("Next:")
    print("  git add -A && git commit -m 'v333: system integrity briefing + feed' && git push")
    print("  then RESTART the backend. The shield 'Integrity' button appears")
    print("  in the briefings strip — click it any time for the live")
    print("  pass/fail scorecard + the regime-demotion audit feed.")


if __name__ == "__main__":
    main()
